def int_to_roman(n):
    if not isinstance(n, int) or isinstance(n, bool):
        raise TypeError("n must be an int")
    if n < 1 or n > 3999:
        raise ValueError("n must be in range 1..3999")
    values = [
        (1000, "M"), (900, "CM"), (500, "D"), (400, "CD"),
        (100, "C"), (90, "XC"), (50, "L"), (40, "XL"),
        (10, "X"), (9, "IX"), (5, "V"), (4, "IV"), (1, "I"),
    ]
    result = []
    for value, symbol in values:
        count, n = divmod(n, value)
        result.append(symbol * count)
    return "".join(result)


def roman_to_int(s):
    if not isinstance(s, str):
        raise TypeError("s must be a str")
    s = s.strip().upper()
    if not s:
        raise ValueError("empty Roman numeral")
    values = {"I": 1, "V": 5, "X": 10, "L": 50, "C": 100, "D": 500, "M": 1000}
    total = 0
    prev = 0
    for ch in reversed(s):
        if ch not in values:
            raise ValueError("invalid Roman numeral character: %r" % ch)
        cur = values[ch]
        if cur < prev:
            total -= cur
        else:
            total += cur
            prev = cur
    if total < 1 or total > 3999:
        raise ValueError("Roman numeral out of range 1..3999")
    if int_to_roman(total) != s:
        raise ValueError("invalid Roman numeral: %r" % s)
    return total
